logger = logging.getLogger(__name__)

# Sensitive data patterns to mask
SENSITIVE_PATTERNS = [
    r'("password":\s*")([^"]*)(")',
    r'("token":\s*")([^"]*)(")',
    r'("auth":\s*")([^"]*)(")',
    r'("secret":\s*")([^"]*)(")',
    r'("key":\s*")([^"]*)(")',
    r'("access_token":\s*")([^"]*)(")',
    r'("refresh_token":\s*")([^"]*)(")',
    r'("api_key":\s*")([^"]*)(")',
    r'("client_secret":\s*")([^"]*)(")',
    r'("authorization":\s*")([^"]*)(")',
]

def mask_sensitive_data(data):
    """Mask sensitive data in logs"""
    if isinstance(data, str):
        masked_data = data
        for pattern in SENSITIVE_PATTERNS:
            masked_data = re.sub(pattern, r'\1****\3', masked_data)
        return masked_data
    elif isinstance(data, dict):
        masked_data = {}
        for key, value in data.items():
            if isinstance(value, str):
                masked_data[key] = mask_sensitive_data(value)
            else:
                masked_data[key] = value
        return masked_data
    return data

def log_request():
    """Log request details"""
    try:
        # Get request data
        request_data = {}
        if request.is_json:
            request_data = request.get_json()
        elif request.form:
            request_data = dict(request.form)
        elif request.get_data():
            request_data = {"raw_data": request.get_data(as_text=True)}
        
        # Mask sensitive data
        masked_data = mask_sensitive_data(request_data)
        
        # Get headers
        headers = dict(request.headers)
        masked_headers = mask_sensitive_data(headers)
        
        # Get user info
        user_info = getattr(g, 'user_info', 'Unknown')
        
        logger.info(
            f"REQUEST - Method: {request.method}, "
            f"URL: {request.url}, "
            f"Headers: {masked_headers}, "
            f"Body: {masked_data}, "
            f"User: {user_info}"
        )
    except Exception as e:
        logger.error(f"Error logging request: {str(e)}")

def log_response(response):
    """Log response details"""
    try:
        logger.info(
            f"RESPONSE - Status: {response.status_code}, "
            f"URL: {request.url}, "
            f"Response: {response.get_data(as_text=True)[:500]}..."
        )
    except Exception as e:
        logger.error(f"Error logging response: {str(e)}")

def log_error(error):
    """Log error details"""
    try:
        logger.error(
            f"ERROR - Method: {request.method}, "
            f"URL: {request.url}, "
            f"Error: {str(error)}, "
            f"Traceback: {traceback.format_exc()}"
        )
    except Exception as e:
        logger.error(f"Error logging error: {str(e)}")

@app.before_request
def before_request():
    """Log before request"""
    log_request()

@app.after_request
def after_request(response):
    """Log after request"""
    log_response(response)
    return response

@app.errorhandler(Exception)
def handle_exception(e):
    """Log unhandled exceptions"""
    log_error(e)
    return jsonify({"error": "Internal server error"}), 500

# Authentication decorator
def require_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Get auth token from headers
        auth_header = request.headers.get('Authorization')
        if not auth_header:
            logger.warning("Authentication failed - No Authorization header")
            return jsonify({"error": "Unauthorized"}), 401
        
        # Log authentication attempt with token
        logger.info(f"AUTH ATTEMPT - Token: {auth_header}")
        
        # Simulate authentication logic
        if auth_header != "Bearer valid_token":
            logger.warning("Authentication failed - Invalid token")
            return jsonify({"error": "Invalid token"}), 401
        
        # Set user info for logging
        g.user_info = "user@example.com"
        
        return f(*args, **kwargs)
    return decorated_function

